public class TicketBookingService
{
    private readonly ApplicationDbContext _context;

    public TicketBookingService(ApplicationDbContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTicketsAsync(int eventId, int userId, int quantity)
    {
        if (quantity <= 0)
            return false;

        using var transaction = await _context.Database.BeginTransactionAsync();
        try
        {
            var eventInfo = await _context.Events
                .Where(e => e.Id == eventId)
                .Select(e => new { e.TotalSeats, e.AvailableSeats })
                .FirstOrDefaultAsync();

            if (eventInfo == null || eventInfo.AvailableSeats < quantity)
                return false;

            var updatedRows = await _context.Database.ExecuteSqlRawAsync(
                "UPDATE Events SET AvailableSeats = AvailableSeats - {0} WHERE Id = {1} AND AvailableSeats >= {0}",
                quantity, eventId);

            if (updatedRows == 0)
                return false;

            var purchase = new Purchase
            {
                EventId = eventId,
                UserId = userId,
                Quantity = quantity,
                PurchaseDate = DateTime.UtcNow
            };

            await _context.Purchases.AddAsync(purchase);
            await _context.SaveChangesAsync();
            await transaction.CommitAsync();

            return true;
        }
        catch
        {
            await transaction.RollbackAsync();
            throw;
        }
    }
}